create table dirkspzm32.pe_eti_drucker_cmd (
    lp_type          varchar2(50 char) not null enable,
    command          varchar2(100 char) not null enable,
    pattern          varchar2(2000 char),
    info             varchar2(255 char),
    rotation0_text   varchar2(10 char),
    rotation90_text  varchar2(10 char),
    rotation180_text varchar2(10 char),
    rotation270_text varchar2(10 char),
    x_offset         number(*, 5),
    y_offset         number(*, 5),
    params           varchar2(255 char)
);

alter table dirkspzm32.pe_eti_drucker_cmd
    add constraint pk_eti_drucker_cmd primary key ( lp_type,
                                                    command )
        using index enable;


